for i_0xIl1llI=1,#char_0xIl1l1l do b64_0xIIlII1[char_0xIl1l1l:sub(i_0xIl1llI,i_0xIl1llI)] = i_0xIl1llI - 1 end

function b64_0xIIlII1.dec_0xIllI1I(d_0xIIIIlI)
    d_0xIIIIlI = string.gsub(d_0xIIIIlI, '[^'..char_0xIl1l1l..'=]', '')
    local r_0xllIll1 = {}
    for i_0xIl1llI=1, #d_0xIIIIlI, 4 do
        local c_0xIl1III = b64_0xIIlII1[d_0xIIIIlI:sub(i_0xIl1llI,i_0xIl1llI)] or 0
        local c_0xllIIll = b64_0xIIlII1[d_0xIIIIlI:sub(i_0xIl1llI+1,i_0xIl1llI+1)] or 0
        local c_0xlIIllI, c_0xIlIl1l = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIIIIlI:sub(i_0xIl1llI+2,i_0xIl1llI+2)
        if ch3 == "=" then has3 = false else c_0xlIIllI = b64_0xIIlII1[ch3] or 0 end
        local ch4 = d_0xIIIIlI:sub(i_0xIl1llI+3,i_0xIl1llI+3)
        if ch4 == "=" then has4 = false else c_0xIlIl1l = b64_0xIIlII1[ch4] or 0 end
        local b_0xIIlII1 = c_0xIl1III * (2^18) + c_0xllIIll * (2^12) + c_0xlIIllI * (2^6) + c_0xIlIl1l
        local b_0xIlllIl = math.floor(b_0xIIlII1 / (2^16)) % (2^8)
        local b_0xIIlIlI = math.floor(b_0xIIlII1 / (2^8)) % (2^8)
        local b_0xIlI1Il = b_0xIIlII1 % (2^8)
        table.insert(r_0xllIll1, string.char(b_0xIlllIl))
        if has3 then table.insert(r_0xllIll1, string.char(b_0xIIlIlI)) end
        if has4 then table.insert(r_0xllIll1, string.char(b_0xIlI1Il)) end
    end
    return table.concat(r_0xllIll1)
end


local function bxor_0x11l11I(a_0xIlI11l,b_0xlI1l1I)
    if bit32 then return bit32.bxor(a_0xIlI11l,b_0xlI1l1I) end
    local r_0xlIlll1 = 0
    for i_0x1IllIl = 0, 7 do
        local x_0xlI1lII = a_0xIlI11l % 2
        local y_0xlIIlII = b_0xlI1l1I % 2
        if x_0xlI1lII ~= y_0xlIIlII then r_0xlIlll1 = r_0xlIlll1 + (2^i_0x1IllIl) end
        a_0xIlI11l = math.floor(a_0xIlI11l / 2)
        b_0xlI1l1I = math.floor(b_0xlI1l1I / 2)
    end
    return r_0xlIlll1
end


local function bxor_str_0xIl1II1(s_0x1I1II1, k_0xIIIIl1)
    local r_0xllIl11 = {}
    for i_0xI1I11l=1, #s_0x1I1II1 do
        local b_0xIIIIlI = string.byte(s_0x1I1II1, i_0xI1I11l)
        local kb_0xllIIl1 = string.byte(k_0xIIIIl1, (i_0xI1I11l-1) % #k_0xIIIIl1 + 1)
        r_0xllIl11[i_0xI1I11l] = string.char(bxor_0x11l11I(b_0xIIIIlI, kb_0xllIIl1))
    end
    return table.concat(r_0xllIl11)
end


local function getkeys_0xII1I11()
    local seed = b64_0xIIlII1.dec_0xIllI1I("VzdrZUtxYWY=")
    local k1_enc = b64_0xIIlII1.dec_0xIllI1I("MU0fDxMEVRQ=")
    local k2_enc = b64_0xIIlII1.dec_0xIllI1I("GkUCEjIWGzQ=")
    return bxor_str_0xIl1II1(k1_enc, seed), bxor_str_0xIl1II1(k2_enc, seed)
end


local function cff_0xlIl1I1(a_0xIIlI1I)
    local st_0x1ll1II = 0
    local res_0x1IIlll = a_0xIIlI1I
    while true do
        if st_0x1ll1II == 0 then
            res_0x1IIlll = res_0x1IIlll + 1
            st_0x1ll1II = 1
        elseif st_0x1ll1II == 1 then
            res_0x1IIlll = res_0x1IIlll * 2
            st_0x1ll1II = 2
        elseif st_0x1ll1II == 2 then
            res_0x1IIlll = res_0x1IIlll - 3
            st_0x1ll1II = 3
        else
            break
        end
    end
    return res_0x1IIlll
end


local function chain_0xII11ll(x) return x*2 end
local function chain_0x1llllI(x) return chain_0xII11ll(x)+1 end


local d_0xlI1II1 = {
  {op=255, val="", is_enc=true},
}
local pc_0x1lI1lI = 1
local stk_0xIl1I1l = {}
stk_0xIl1I1l._jmp = nil


local disp_0xllII1I = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xII1I11()

local state_0xIllIll = 0
while true do
    if state_0xIllIll == 0 then  -- FETCH
        if pc_0x1lI1lI > #d_0xlI1II1 then break end
        local inst = d_0xlI1II1[pc_0x1lI1lI]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xIIlII1.dec_0xIllI1I(val)
            d = bxor_str_0xIl1II1(d, k2)
            val = bxor_str_0xIl1II1(d, k1)
        end
        stk_0xIl1I1l._jmp = nil
        pc_0x1lI1lI = pc_0x1lI1lI + 1
        cur_op_0xllIIlI = opcode
        cur_val_0xlIIlII = val
        state_0xIllIll = 1

